<script>
// @ is an alias to /src
import http from "@/network/Base.js";
import { mapState } from "vuex";

export default {
  name: "home",
  computed: {
    ...mapState({
      userInfo: state => state.authStore.userInfo,
      loggedIn: state => state.authStore.loggedIn
    }),
    getGreeting() {
      const greeting = [
        "Ola",
        "Hello",
        "Hi",
        "Welcome",
        "Howdy",
        "Good to see you"
      ];
      return greeting[Math.floor(Math.random() * greeting.length)];
    },
    getTimeOfDay() {
      const hr = new Date().getHours();
      if (hr < 12) return "Morning";
      else if (hr < 17) return "Afternoon";
      else return "Evening";
    }
  },
  methods: {
    goToAppointments() {
      this.$router.push({ name: "appointments-route" });
    },
    goToVitals() {
      this.$router.push({ name: "vitals-route" });
    },
    goToPrescriptions() {
      this.$router.push({ name: "prescriptions-route" });
    },
    goToLabs() {
      this.$router.push({ name: "labs-route" });
    },
    goToImaging() {
      this.$router.push({ name: "imagings-route" });
    },
    goToMedicalHistory() {
      this.$router.push({ name: "development-route" });
    },
    getVisits() {
      this.loading = true;
      http()
        .get(`/visits?patientId=${this.userInfo.sz_userid}`)
        .then(({ data }) => {
          this.allAppts = data;
        })
        .catch(error => {
          this.loading = false;
          // console.log(error)
          // this.$snotify.error('Sorry, cannot get Service detail')
        })
        .finally(() => {
          this.loading = false;
        });
    }
  },
  created() {
    this.getVisits();
  }
};
</script>

